// MARK: - Models

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
    case payment
}

enum TransactionStatus: String, Codable {
    case pending
    case completed
    case failed
    case cancelled
}

enum Currency: String, Codable {
    case usd = "USD"
    case eur = "EUR"
    case gbp = "GBP"
}

struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: Currency
    let fromAccountId: String
    let toAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String

    init(type: TransactionType, amount: Decimal, currency: Currency, fromAccountId: String, toAccountId: String? = nil, description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.fromAccountId = fromAccountId
        self.toAccountId = toAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }

    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 1000...9999)
        return "TXN-\(timestamp)-\(random)"
    }
}

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountHolderName: String
    var balance: Decimal
    let currency: Currency
    let createdAt: Date
    var isActive: Bool

    var maskedAccountNumber: String {
        let suffix = String(accountNumber.suffix(4))
        return "****\(suffix)"
    }
}

struct TransactionResult {
    let success: Bool
    let transaction: Transaction
    let message: String
    let updatedBalance: Decimal?
}

// MARK: - Encryption Service

final class EncryptionService {

    private static let keychainServiceIdentifier = "com.bankingapp.encryption"
    private static let symmetricKeyTag = "com.bankingapp.symmetrickey"

    // MARK: - Symmetric Key Management

    static func getOrCreateSymmetricKey() throws -> SymmetricKey {
        if let existingKey = try retrieveSymmetricKeyFromKeychain() {
            return existingKey
        }
        let newKey = SymmetricKey(size: .bits256)
        try storeSymmetricKeyInKeychain(newKey)
        return newKey
    }

    private static func storeSymmetricKeyInKeychain(_ key: SymmetricKey) throws {
        let keyData = key.withUnsafeBytes { Data($0) }

        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceIdentifier,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]

        SecItemDelete(query as CFDictionary)

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw EncryptionError.keychainStoreFailed(status)
        }
    }

    private static func retrieveSymmetricKeyFromKeychain() throws -> SymmetricKey? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceIdentifier,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        guard status == errSecSuccess, let keyData = result as? Data else {
            if status == errSecItemNotFound {
                return nil
            }
            throw EncryptionError.keychainRetrieveFailed(status)
        }

        return SymmetricKey(data: keyData)
    }

    // MARK: - Encrypt / Decrypt

    static func encrypt(_ data: Data) throws -> Data {
        let key = try getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        return combined
    }

    static func decrypt(_ data: Data) throws -> Data {
        let key = try getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }

    static func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidInput
        }
        return try encrypt(data)
    }

    static func decryptToString(_ data: Data) throws -> String {
        let decryptedData = try decrypt(data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }

    // MARK: - Hashing

    static func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.compactMap { String(format: "%02x", $0) }.joined()
    }

    static func hashString(_ string: String) -> String {
        guard let data = string.data(using: .utf8) else { return "" }
        return hashData(data)
    }

    // MARK: - HMAC for Transaction Integrity

    static func generateHMAC(for data: Data) throws -> Data {
        let key = try getOrCreateSymmetricKey()
        let hmac = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(hmac)
    }

    static func verifyHMAC(_ hmac: Data, for data: Data) throws -> Bool {
        let key = try getOrCreateSymmetricKey()
        return HMAC<SHA256>.isValidAuthenticationCode(hmac, authenticating: data, using: key)
    }
}

enum EncryptionError: Error, LocalizedError {
    case keychainStoreFailed(OSStatus)
    case keychainRetrieveFailed(OSStatus)
    case encryptionFailed
    case decryptionFailed
    case invalidInput

    var errorDescription: String? {
        switch self {
        case .keychainStoreFailed(let status):
            return "Failed to store key in Keychain (status: \(status))"
        case .keychainRetrieveFailed(let status):
            return "Failed to retrieve key from Keychain (status: \(status))"
        case .encryptionFailed:
            return "Encryption failed"
        case .decryptionFailed:
            return "Decryption failed"
        case .invalidInput:
            return "Invalid input for encryption"
        }
    }
}

// MARK: - Secure Storage

final class SecureStorage {

    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    func saveEncrypted<T: Encodable>(_ object: T, forKey key: String) throws {
        let data = try encoder.encode(object)
        let encryptedData = try EncryptionService.encrypt(data)
        UserDefaults.standard.set(encryptedData, forKey: key)
    }

    func loadDecrypted<T: Decodable>(_ type: T.Type, forKey key: String) throws -> T? {
        guard let encryptedData = UserDefaults.standard.data(forKey: key) else {
            return nil
        }
        let decryptedData = try EncryptionService.decrypt(encryptedData)
        return try decoder.decode(type, from: decryptedData)
    }

    func removeData(forKey key: String) {
        UserDefaults.standard.removeObject(forKey: key)
    }
}

// MARK: - Transaction Validation

struct TransactionValidator {

    enum ValidationError: Error, LocalizedError {
        case insufficientFunds
        case invalidAmount
        case accountInactive
        case dailyLimitExceeded
        case sameAccountTransfer
        case accountNotFound

        var errorDescription: String? {
            switch self {
            case .insufficientFunds: return "Insufficient funds for this transaction"
            case .invalidAmount: return "Transaction amount must be greater than zero"
            case .accountInactive: return "Account is not active"
            case .dailyLimitExceeded: return "Daily transaction limit exceeded"
            case .sameAccountTransfer: return "Cannot transfer to the same account"
            case .accountNotFound: return "Account not found"
            }
        }
    }

    static let dailyTransactionLimit: Decimal = 50000.00

    static func validate(transaction: Transaction, account: Account, dailyTotal: Decimal) throws {
        guard account.isActive else {
            throw ValidationError.accountInactive
        }

        guard transaction.amount > 0 else {
            throw ValidationError.invalidAmount
        }

        if transaction.type == .transfer {
            guard transaction.toAccountId != nil, transaction.toAccountId != transaction.fromAccountId else {
                throw ValidationError.sameAccountTransfer
            }
        }

        if transaction.type == .withdrawal || transaction.type == .transfer || transaction.type == .payment {
            guard account.balance >= transaction.amount else {
                throw ValidationError.insufficientFunds
            }

            guard (dailyTotal + transaction.amount) <= dailyTransactionLimit else {
                throw ValidationError.dailyLimitExceeded
            }
        }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {

    private let secureStorage = SecureStorage()
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactionprocessor", qos: .userInitiated)

    private static let accountsStorageKey = "encrypted_accounts"
    private static let transactionsStorageKey = "encrypted_transactions"

    private var accounts: [String: Account] = [:]
    private var transactionHistory: [Transaction] = []

    init() {
        loadPersistedData()
    }

    // MARK: - Account Management

    func createAccount(accountNumber: String, holderName: String, initialBalance: Decimal, currency: Currency) -> Account {
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountHolderName: holderName,
            balance: initialBalance,
            currency: currency,
            createdAt: Date(),
            isActive: true
        )
        accounts[account.id] = account
        persistAccounts()
        return account
    }

    func getAccount(byId id: String) -> Account? {
        return accounts[id]
    }

    func getAllAccounts() -> [Account] {
        return Array(accounts.values)
    }

    func getBalance(forAccountId accountId: String) -> Decimal? {
        return accounts[accountId]?.balance
    }

    // MARK: - Transaction Processing

    func processTransaction(_ transaction: Transaction, completion: @escaping (Result<TransactionResult, Error>) -> Void) {
        transactionQueue.async { [weak self] in
            guard let self = self else { return }

            var mutableTransaction = transaction

            do {
                guard let account = self.accounts[transaction.fromAccountId] else {
                    throw TransactionValidator.ValidationError.accountNotFound
                }

                let dailyTotal = self.calculateDailyTotal(forAccountId: transaction.fromAccountId)

                try TransactionValidator.validate(
                    transaction: transaction,
                    account: account,
                    dailyTotal: dailyTotal
                )

                // Verify transaction integrity
                try self.verifyTransactionIntegrity(transaction)

                // Process based on type
                switch transaction.type {
                case .deposit:
                    self.accounts[transaction.fromAccountId]?.balance += transaction.amount

                case .withdrawal:
                    self.accounts[transaction.fromAccountId]?.balance -= transaction.amount

                case .transfer:
                    guard let toAccountId = transaction.toAccountId,
                          self.accounts[toAccountId] != nil else {
                        throw TransactionValidator.ValidationError.accountNotFound
                    }
                    self.accounts[transaction.fromAccountId]?.balance -= transaction.amount
                    self.accounts[toAccountId]?.balance += transaction.amount

                case .payment:
                    self.accounts[transaction.fromAccountId]?.balance -= transaction.amount
                }

                mutableTransaction.status = .completed
                self.transactionHistory.append(mutableTransaction)

                // Persist
                self.persistAccounts()
                self.persistTransactions()

                let updatedBalance = self.accounts[transaction.fromAccountId]?.balance

                let result = TransactionResult(
                    success: true,
                    transaction: mutableTransaction,
                    message: "Transaction completed successfully",
                    updatedBalance: updatedBalance
                )

                DispatchQueue.main.async {
                    completion(.success(result))
                }

            } catch {
                mutableTransaction.status = .failed
                self.transactionHistory.append(mutableTransaction)
                self.persistTransactions()

                DispatchQueue.main.async {
                    completion(.failure(error))
                }
            }
        }
    }

    func processTransactionAsync(_ transaction: Transaction) async throws -> TransactionResult {
        return try await withCheckedThrowingContinuation { continuation in
            processTransaction(transaction) { result in
                switch result {
                case .success(let transactionResult):
                    continuation.resume(returning: transactionResult)
                case .failure(let error):
                    continuation.resume(throwing: error)
                }
            }
        }
    }

    // MARK: - Transaction History

    func getTransactionHistory(forAccountId accountId: String) -> [Transaction] {
        return transactionHistory.filter {
            $0.fromAccountId == accountId || $0.toAccountId == accountId
        }.sorted { $0.timestamp > $1.timestamp }
    }

    func getTransactionHistory(forAccountId accountId: String, dateRange: ClosedRange<Date>) -> [Transaction] {
        return getTransactionHistory(forAccountId: accountId).filter {
            dateRange.contains($0.timestamp)
        }
    }

    func getAllTransactions() -> [Transaction] {
        return transactionHistory.sorted { $0.timestamp > $1.timestamp }
    }

    // MARK: - Private Helpers

    private func calculateDailyTotal(forAccountId accountId: String) -> Decimal {
        let calendar = Calendar.current
        let today = calendar.startOfDay(for: Date())

        return transactionHistory
            .filter { $0.fromAccountId == accountId &&
                      $0.status == .completed &&
                      ($0.type == .withdrawal || $0.type == .transfer || $0.type == .payment) &&
                      calendar.isDate($0.timestamp, inSameDayAs: today)
            }
            .reduce(Decimal.zero) { $0 + $1.amount }
    }

    private func verifyTransactionIntegrity(_ transaction: Transaction) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(transaction)
        _ = try EncryptionService.generateHMAC(for: data)
        // In production, store and verify HMAC with each transaction
    }

    // MARK: - Persistence

    private func persistAccounts() {
        do {
            try secureStorage.saveEncrypted(accounts, forKey: Self.accountsStorageKey)
        } catch {
            print("Failed to persist accounts: \(error.localizedDescription)")
        }
    }

    private func persistTransactions() {
        do {
            try secureStorage.saveEncrypted(transactionHistory, forKey: Self.transactionsStorageKey)
        } catch {
            print("Failed to persist transactions: \(error.localizedDescription)")
        }
    }

    private func loadPersistedData() {
        do {
            if let loadedAccounts: [String: Account] = try secureStorage.loadDecrypted([String: Account].self, forKey: Self.accountsStorageKey) {
                accounts = loadedAccounts
            }
            if let loadedTransactions: [Transaction] = try secureStorage.loadDecrypted([Transaction].self, forKey: Self.transactionsStorageKey) {
                transactionHistory = loadedTransactions
            }
        } catch {
            print("Failed to load persisted data: \(error.localizedDescription)")
        }
    }
}

// MARK: - Account Balance View Model

import SwiftUI

@MainActor
final class AccountBalanceViewModel: ObservableObject {

    @Published var accounts: [Account] = []
    @Published var selectedAccount: Account?
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var successMessage: String?

    private let processor = TransactionProcessor()

    func loadAccounts() {
        accounts = processor.getAllAccounts()
        if accounts.isEmpty {
            seedDemoAccounts()
        }
    }

    func selectAccount(_ account: Account) {
        selectedAccount = account
        loadTransactions(forAccountId: account.id)
    }

    func loadTransactions(forAccountId accountId: String) {
        transactions = processor.getTransactionHistory(forAccountId: accountId)
    }

    func performDeposit(amount: Decimal, description: String) async {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }

        isLoading = true
        errorMessage = nil
        successMessage = nil

        let transaction = Transaction(
            type: .deposit,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            description: description
        )

        do {
            let result = try await processor.processTransactionAsync(transaction)
            successMessage = result.message
            refreshData()
        } catch {
            errorMessage = error.localizedDescription
        }

        isLoading = false
    }

    func performWithdrawal(amount: Decimal, description: String) async {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }

        isLoading = true
        errorMessage = nil
        successMessage = nil

        let transaction = Transaction(
            type: .withdrawal,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            description: description
        )

        do {
            let result = try await processor.processTransactionAsync(transaction)
            successMessage = result.message
            refreshData()
        } catch {
            errorMessage = error.localizedDescription
        }

        isLoading = false
    }

    func performTransfer(amount: Decimal, toAccountId: String, description: String) async {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }

        isLoading = true
        errorMessage = nil
        successMessage = nil

        let transaction = Transaction(
            type: .transfer,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            toAccountId: toAccountId,
            description: description
        )

        do {
            let result = try await processor.processTransactionAsync(transaction)
            successMessage = result.message
            refreshData()
        } catch {
            errorMessage = error.localizedDescription
        }

        isLoading = false
    }

    private func refreshData() {
        accounts = processor.getAllAccounts()
        if let selectedId = selectedAccount?.id {
            selectedAccount = accounts.first { $0.id == selectedId }
            loadTransactions(forAccountId: selectedId)
        }
    }

    private func seedDemoAccounts() {
        let checking = processor.createAccount(
            accountNumber: "1234567890",
            holderName: "John Doe",
            initialBalance: 5000.00,
            currency: .usd
        )
        let savings = processor.createAccount(
            accountNumber: "0987654321",
            holderName: "John Doe",
            initialBalance: 25000.00,
            currency: .usd
        )
        accounts = [checking, savings]
    }
}

