    private var isCredit: Bool {
        if transaction.type == .deposit { return true }
        if transaction.type == .transfer && transaction.toAccountId == accountId { return true }
        return false
    }

    private var icon: String {
        switch transaction.type {
        case .deposit: return "arrow.down.circle.fill"
        case .withdrawal: return "arrow.up.circle.fill"
        case .transfer: return "arrow.left.arrow.right.circle.fill"
        case .payment: return "creditcard.fill"
        }
    }

    private var iconColor: Color {
        switch transaction.status {
        case .completed: return isCredit ? .green : .orange
        case .failed: return .red
        case .pending: return .yellow
        case .cancelled: return .gray
        }
    }

    private var dateFormatter: DateFormatter {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter
    }

    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: icon)
                .font(.title3)
                .foregroundColor(iconColor)
                .frame(width: 40, height: 40)
                .background(iconColor.opacity(0.1))
                .cornerRadius(10)

            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .lineLimit(1)

                HStack(spacing: 4) {
                    Text(transaction.type.rawValue.capitalized)
                        .font(.caption2)
                        .foregroundColor(.secondary)
                    Text("•")
                        .font(.caption2)
                        .foregroundColor(.secondary)
                    Text(dateFormatter.string(from: transaction.timestamp))
                        .font(.caption2)
                        .foregroundColor(.secondary)
                }
            }

            Spacer()

            VStack(alignment: .trailing, spacing: 4) {
                Text("\(isCredit ? "+" : "-")\(currencySymbol)\(NSDecimalNumber(decimal: transaction.amount).doubleValue, specifier: "%.2f")")
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(isCredit ? .green : .primary)

                TransactionStatusBadge(status: transaction.status)
            }
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 12)
    }
}

struct TransactionStatusBadge: View {
    let status: TransactionStatus

    private var color: Color {
        switch status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }

    var body: some View {
        Text(status.rawValue.capitalized)
            .font(.system(size: 10, weight: .medium))
            .foregroundColor(color)
            .padding(.horizontal, 6)
            .padding(.vertical, 2)
            .background(color.opacity(0.1))
            .cornerRadius(4)
    }
}

struct AlertBanner: View {
    let message: String
    let type: AlertType

    enum AlertType {
        case success, error
    }

    var body: some View {
        HStack(spacing: 8) {
            Image(systemName: type == .success ? "checkmark.circle.fill" : "exclamationmark.circle.fill")
                .foregroundColor(type == .success ? .green : .red)
            Text(message)
                .font(.subheadline)
                .foregroundColor(type == .success ? .green : .red)
            Spacer()
        }
        .padding()
        .background((type == .success ? Color.green : Color.red).opacity(0.1))
        .cornerRadius(12)
    }
}

struct TransactionFormView: View {
    let type: TransactionType
    @ObservedObject var viewModel: AccountBalanceViewModel
    @Environment(\.dismiss) private var dismiss

    @State private var amountString = ""
    @State private var description = ""
    @State private var toAccountId = ""

    private var title: String {
        switch type {
        case .deposit: return "Deposit"
        case .withdrawal: return "Withdrawal"
        case .transfer: return "Transfer"
        case .payment: return "Payment"
        }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Amount")) {
                    TextField("0.00", text: $amountString)
                        .keyboardType(.decimalPad)
                        .font(.title2)
                }

                Section(header: Text("Description")) {
                    TextField("Enter description", text: $description)
                }

                if type == .transfer {
                    Section(header: Text("Recipient Account")) {
                        Picker("To Account", selection: $toAccountId) {
                            Text("Select Account").tag("")
                            ForEach(viewModel.accounts.filter { $0.id != viewModel.selectedAccount?.id }) { account in
                                Text("\(account.accountHolderName) - \(account.maskedAccountNumber)").tag(account.id)
                            }
                        }
                    }
                }

                Section {
                    Button(action: submitTransaction) {
                        if viewModel.isLoading {
                            ProgressView()
                                .frame(maxWidth: .infinity)
                        } else {
                            Text("Confirm \(title)")
                                .frame(maxWidth: .infinity)
                                .fontWeight(.semibold)
                        }
                    }
                    .disabled(viewModel.isLoading || amountString.isEmpty)
                }
            }
            .navigationTitle(title)
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") {
                        dismiss()
                    }
                }
            }
        }
    }

    private func submitTransaction() {
        guard let amount = Decimal(string: amountString) else { return }

        Task {
            switch type {
            case .deposit:
                await viewModel.performDeposit(amount: amount, description: description.isEmpty ? "Deposit" : description)
            case .withdrawal:
                await viewModel.performWithdrawal(amount: amount, description: description.isEmpty ? "Withdrawal" : description)
            case .transfer:
                await viewModel.performTransfer(amount: amount, toAccountId: toAccountId, description: description.isEmpty ? "Transfer" : description)
            case .payment:
                await viewModel.performWithdrawal(amount: amount, description: description.isEmpty ? "Payment" : description)
            }

            if viewModel.errorMessage == nil {
                dismiss()
            }
        }
    }
}

