// MARK: - Audit Logger

final class AuditLogger {
    static let shared = AuditLogger()

    private let logQueue = DispatchQueue(label: "com.bankingapp.auditlog", qos: .utility)
    private let secureStorage = SecureStorage()
    private static let logsKey = "encrypted_audit_logs"

    struct AuditEntry: Codable {
        let id: UUID
        let timestamp: Date
        let action: String
        let accountId: String?
        let details: String
        let ipAddress: String?
    }

    private var logs: [AuditEntry] = []

    private init() {
        loadLogs()
    }

    func log(action: String, accountId: String? = nil, details: String) {
        logQueue.async { [weak self] in
            let entry = AuditEntry(
                id: UUID(),
                timestamp: Date(),
                action: action,
                accountId: accountId,
                details: details,
                ipAddress: nil
            )
            self?.logs.append(entry)
            self?.persistLogs()
        }
    }

    func getLogs(forAccountId accountId: String) -> [AuditEntry] {
        return logs.filter { $0.accountId == accountId }
    }

    func getAllLogs() -> [AuditEntry] {
        return logs.sorted { $0.timestamp > $1.timestamp }
    }

    private func persistLogs() {
        do {
            try secureStorage.saveEncrypted(logs, forKey: Self.logsKey)
        } catch {
            print("Failed to persist audit logs: \(error.localizedDescription)")
        }
    }

    private func loadLogs() {
        do {
            if let loadedLogs: [AuditEntry] = try secureStorage.loadDecrypted([AuditEntry].self, forKey: Self.logsKey) {
                logs = loadedLogs
            }
        } catch {
            print("Failed to load audit logs: \(error.localizedDescription)")
        }
    }
}

